<?php
require_once __DIR__ . '/inc/db.php';

if (!function_exists('h')) {
    function h($str) {
        return htmlspecialchars((string)$str, ENT_QUOTES, 'UTF-8');
    }
}

$isLogin   = !empty($_SESSION['is_login']);
$profile   = $_SESSION['member_profile'] ?? '';
$profilePath = $profile ? 'uploads/profile/' . $profile : '';

$totalPostCount  = 0;
$categoryRows    = [];
$allRecommendPosts = [];
$allRecentPosts    = [];

$totalResult = mysqli_query($conn,
    "SELECT COUNT(*) AS cnt FROM blog_posts WHERE status='active' AND is_public='public'"
);
if ($totalResult) {
    $totalPostCount = (int)(mysqli_fetch_assoc($totalResult)['cnt'] ?? 0);
}

$categoryResult = mysqli_query($conn, "
    SELECT c.id, c.name, COUNT(p.id) AS post_count
    FROM blog_categories c
    LEFT JOIN blog_posts p
        ON p.category_id = c.id AND p.status='active' AND p.is_public='public'
    GROUP BY c.id, c.name
    ORDER BY c.id ASC
");
if ($categoryResult) {
    while ($row = mysqli_fetch_assoc($categoryResult)) $categoryRows[] = $row;
}

$recommendResult = mysqli_query($conn, "
    SELECT p.id, p.title, p.content, p.thumbnail, p.created_at, p.view_count, p.category_id,
           m.nickname, c.name AS category_name
    FROM blog_posts p
    LEFT JOIN blog_members m ON p.member_id = m.id
    LEFT JOIN blog_categories c ON p.category_id = c.id
    WHERE p.status='active' AND p.is_public='public'
    ORDER BY p.view_count DESC, p.created_at DESC
    LIMIT 30
");
if ($recommendResult) {
    while ($row = mysqli_fetch_assoc($recommendResult)) $allRecommendPosts[] = $row;
}

$recentResult = mysqli_query($conn, "
    SELECT p.id, p.title, p.content, p.thumbnail, p.created_at, p.category_id,
           m.nickname, c.name AS category_name
    FROM blog_posts p
    LEFT JOIN blog_members m ON p.member_id = m.id
    LEFT JOIN blog_categories c ON p.category_id = c.id
    WHERE p.status='active' AND p.is_public='public'
    ORDER BY p.created_at DESC
    LIMIT 50
");
if ($recentResult) {
    while ($row = mysqli_fetch_assoc($recentResult)) $allRecentPosts[] = $row;
}

function short_text($text, $len = 70) {
    $text = trim(strip_tags((string)$text));
    return mb_strlen($text, 'UTF-8') > $len
        ? mb_substr($text, 0, $len, 'UTF-8') . '...'
        : $text;
}

