<script>
const ALL_RECOMMEND = <?= json_encode($allRecommendPosts, JSON_UNESCAPED_UNICODE) ?>;
const ALL_RECENT    = <?= json_encode($allRecentPosts,    JSON_UNESCAPED_UNICODE) ?>;
const IS_LOGIN      = <?= json_encode($isLogin) ?>;

const iconCal  = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>`;
const iconUser = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/><circle cx="12" cy="7" r="4"/></svg>`;

const fmtDate = dt => (dt || '').slice(0, 10).replace(/-/g, '.');
const shorten = (t, n = 58) => {
    const s = t.replace(/<[^>]*>/g, '').trim();
    return s.length > n ? s.slice(0, n) + '…' : s;
};

function renderRecommend(posts) {
    const el = document.getElementById('recommend-section');
    if (!posts.length) {
        el.innerHTML = '<div class="empty-box">아직 등록된 추천 글이 없습니다.</div>';
        return;
    }
    el.innerHTML = '<div class="recommend-grid">' +
        posts.slice(0, 3).map(p => {
            const thumb = p.thumbnail
                ? `<div class="recommend-thumb"><img src="${p.thumbnail}" alt=""></div>`
                : `<div class="recommend-thumb empty">이미지 없음</div>`;
            return `<article class="recommend-card"><a href="post_view.php?id=${p.id}">
                ${thumb}
                <div class="recommend-info">
                    <h3>${p.title}</h3>
                    <p>${shorten(p.content)}</p>
                    <div class="post-meta">
                        <span class="post-meta-item">${iconCal}${fmtDate(p.created_at)}</span>
                        <span class="post-meta-item">${iconUser}${p.nickname || '알 수 없음'}</span>
                    </div>
                </div>
            </a></article>`;
        }).join('') + '</div>';
}

function renderRecent(posts, catName) {
    document.getElementById('recent-heading').textContent = `최근 ${catName} 글`;
    const el = document.getElementById('recent-section');
    if (!posts.length) {
        el.innerHTML = '<div class="empty-box">아직 등록된 글이 없습니다.' +
            (IS_LOGIN ? '<br><a href="post_write.php">첫 글 작성하기</a>' : '') + '</div>';
        return;
    }
    el.innerHTML = '<div class="recent-list">' +
        posts.slice(0, 5).map(p => {
            const thumb = p.thumbnail
                ? `<img src="${p.thumbnail}" alt="">`
                : '이미지';
            return `<article class="recent-item">
                <a href="post_view.php?id=${p.id}" class="recent-thumb">${thumb}</a>
                <div class="recent-copy">
                    <h3><a href="post_view.php?id=${p.id}">${p.title}</a></h3>
                    <p>${shorten(p.content, 86)}</p>
                </div>
                <div class="recent-meta">
                    <span class="recent-meta-item">${iconCal}${fmtDate(p.created_at)}</span>
                    <span class="recent-meta-item">${iconUser}${p.nickname || '알 수 없음'}</span>
                </div>
            </article>`;
        }).join('') + '</div>';
}

function activateCategory(catId, catName) {
    document.querySelectorAll('.category-card').forEach(c =>
        c.classList.toggle('active', parseInt(c.dataset.catId) === catId)
    );
    document.getElementById('recommend-badge').textContent = `${catName} 카테고리로 필터링됨`;
    renderRecommend(ALL_RECOMMEND.filter(p => parseInt(p.category_id) === catId));
    renderRecent(ALL_RECENT.filter(p => parseInt(p.category_id) === catId), catName);
}

document.querySelectorAll('.category-card').forEach(card => {
    const go = () => activateCategory(parseInt(card.dataset.catId), card.dataset.catName);
    card.addEventListener('click', go);
    card.addEventListener('keydown', e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); go(); } });
});

// 초기 렌더링
const first = document.querySelector('.category-card');
if (first) activateCategory(parseInt(first.dataset.catId), first.dataset.catName);
</script>

